using System.ComponentModel;
using System.ComponentModel.DataAnnotations;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public class ExternalApiTool
{
    [McpServerTool(Name = "fetch_url"), Description("Fetches content from an external URL via HTTP GET.")]
    public static async Task<string> FetchUrlAsync(
        HttpClient httpClient,
        [Description("The absolute URL to fetch.")] [Required] string url,
        CancellationToken cancellationToken)
    {
        using var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public class SummarizationPrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a summarization prompt for the given content.")]
    public static string Summarize(
        [Description("The text content to summarize.")] string content,
        [Description("Optional target style, e.g. 'brief', 'detailed', 'bullet-points'.")] string? style = null)
    {
        var instruction = style is not null
            ? $"Summarize the following content in a {style} style."
            : "Provide a concise summary of the following content.";

        return $"{instruction}\n\n{content}";
    }
}

